 96→        e.stopPropagation();
 97→        const source = notification?.source || 'journal';
 98→        mutationReadNotif.mutate({notifId: notification.id, source})
 99→
100→        if(source === 'opinion'){
101→            handleClickOpinionNotif(e, notification?.opinions?.id, notification?.opinions?.user_id)
102→        } else if(notification?.type === 'repost' && notification?.repost_journal_id){
103→            // Navigate to the repost post (quote + embedded original)
104→            const repostId = notification.repost_journal_id;
105→            const encodedId = encodeURIComponent(repostId);
106→            navigate(`/home/post/${encodedId}`);
107→        } else {
108→            const parsedContent = ParseContent(notification?.journals?.content);
109→            handleClickNotif(
110→                e,
111→                notification?.journals?.content,
112→                parsedContent.wholeText,
113→                notification?.journals?.title,
114→                notification?.journals?.users.id,
115→                notification?.journals?.users?.name,
116→                notification?.journals?.users?.image_url,
117→                notification?.journals?.created_at,
118→                notification?.journal_id,
119→                notification?.hasLiked,
120→                notification?.journals?.comments[0].count,
121→                notification?.hasBookMarked,
122→                notification?.journals?.likes[0].count,
123→                notification?.journals?.bookmarks[0].count,
124→                notification?.journals?.users?.badge,
125→            )
126→        }
