 73→        return next();
 74→    }
 75→
 76→    const { user } = await resolveAuthUser(token);
 77→    if (user?.id) {
 78→        req.userId = user.id;
 79→        req.authUser = user;
 80→    }
 81→
 82→    return next();
 83→};
