153→export const getViewportConstellationsService = async (postIds) => {
154→    if (!Array.isArray(postIds) || postIds.length === 0) {
155→        return [];
156→    }
157→
158→    const { data, error } = await supabase.rpc('get_viewport_constellations', {
159→        post_ids: postIds,
160→    });
161→
162→    if (error) {
163→        console.error('supabase error fetching viewport constellations:', error.message);
164→        throw { status: 500, error: 'error fetching constellations' };
165→    }
166→
167→    return data || [];
168→};
